import hashlib
import uuid
from enum import Enum
from datetime import datetime

class InteractionType(Enum):
    LIKE = 1
    RATING = 2
    UPLOAD = 3
    SETTINGS_CHANGE = 4

class UserInteraction:
    def __init__(self, user_id, interaction_type, timestamp, data):
        self.user_id = user_id
        self.interaction_type = interaction_type
        self.timestamp = timestamp
        self.data = data

class BackendEngine:
    def __init__(self):
        self.interactions = {}

    def add_interaction(self, user_id, interaction_type, data):
        hashed_user_id = self._hash_user_id(user_id)
        if hashed_user_id not in self.interactions:
            self.interactions[hashed_user_id] = []
        interaction = UserInteraction(hashed_user_id, interaction_type, datetime.now(), data)
        self.interactions[hashed_user_id].append(interaction)

    def get_interactions(self, user_id):
        hashed_user_id = self._hash_user_id(user_id)
        return self.interactions.get(hashed_user_id, [])

    def _hash_user_id(self, user_id):
        return hashlib.sha256(str(user_id).encode()).hexdigest()

    def add_new_interaction_type(self, interaction_type):
        InteractionType[interaction_type.name] = len(InteractionType) + 1

    def anonymize_data(self, data):
        anonymized_data = {}
        for key, value in data.items():
            if key != 'user_id':
                anonymized_data[key] = value
        return anonymized_data

engine = BackendEngine()

def main():
    user_id = str(uuid.uuid4())
    engine.add_interaction(user_id, InteractionType.LIKE, {'item_id': 1})
    engine.add_interaction(user_id, InteractionType.RATING, {'item_id': 2, 'rating': 5})
