    RATING = 2
    UPLOAD = 3
    SETTINGS_CHANGE = 4

class Interaction:
    def __init__(self, interaction_type: InteractionType, user_id: str, data: Dict):
        self.interaction_type = interaction_type
        self.user_id = user_id
        self.data = data
        self.timestamp = datetime.now()

class User:
    def __init__(self, user_id: str):
        self.user_id = user_id
        self.interactions = []

    def add_interaction(self, interaction: Interaction):
        self.interactions.append(interaction)

class BackendEngine:
    def __init__(self):
        self.users = {}

    def create_user(self, user_id: str):
        if user_id not in self.users:
            self.users[user_id] = User(user_id)

    def add_interaction(self, user_id: str, interaction_type: InteractionType, data: Dict):
        if user_id in self.users:
            interaction = Interaction(interaction_type, user_id, data)
            self.users[user_id].add_interaction(interaction)

    def get_user_interactions(self, user_id: str):
        if user_id in self.users:
            return self.users[user_id].interactions
        else:
            return []

    def anonymize_user_id(self, user_id: str):
        return hashlib.sha256(user_id.encode()).hexdigest()

    def get_anonymized_user_interactions(self, user_id: str):
        anonymized_user_id = self.anonymize_user_id(user_id)
        interactions = self.get_user_interactions(user_id)
        anonymized_interactions = []
        for interaction in interactions:
            anonymized_interaction = {
                'interaction_type': interaction.interaction_type,
                'data': interaction.data,
                'timestamp': interaction.timestamp
            }
            anonymized_interactions.append(anonymized_interaction)
        return anonymized_interactions

