class TrackManager:
    def __init__(self):
        self.tracks = {}
        self.track_id_counter = 0

    def create_track(self, track_name, track_type):
        self.track_id_counter += 1
        track_id = hash((track_name, track_type, self.track_id_counter))
        track = Track(track_id, track_name, track_type)
        self.tracks[track_id] = track
        return track_id

    def get_track(self, track_id):
        return self.tracks.get(track_id)

    def add_interaction(self, track_id, interaction_type, interaction_value):
        track = self.get_track(track_id)
        if track:
            track.add_interaction(interaction_type, interaction_value)

    def get_interactions(self, track_id, interaction_type):
