    def __init__(self):
        self.tracks = {}
        self.id_counter = 0

    def add_track(self, track_name, track_type):
        self.id_counter += 1
        self.tracks[self.id_counter] = {
            'track_name': track_name,
            'track_type': track_type,
            'likes': 0,
            'ratings': [],
            'keywords': [],
            'query_history': []
        }
        return self.id_counter

    def update_track(self, track_id, track_data):
        if track_id in self.tracks:
            for key, value in track_data.items():
                if key in self.tracks[track_id]:
                    self.tracks[track_id][key] = value
                elif key == 'rating':
                    self.tracks[track_id]['ratings'].append(value)
                elif key == 'keyword':
                    self.tracks[track_id]['keywords'].append(value)
                elif key == 'query':
                    self.tracks[track_id]['query_history'].append(value)
                elif key == 'like':
                    self.tracks[track_id]['likes'] += 1
        else:
            raise ValueError('Track not found')

    def get_track(self, track_id):
        if track_id in self.tracks:
            return self.tracks[track_id]
        else:
            raise ValueError('Track not found')

    def anonymize_track(self, track_id):
        if track_id in self.tracks:
            track_data = self.tracks[track_id]
            del track_data['track_name']
            return track_data
        else:
            raise ValueError('Track not found')

    def hash_track(self, track_id):
        if track_id in self.tracks:
            import hashlib
            track_data = str(self.tracks[track_id]).encode('utf-8')
            return hashlib.sha256(track_data).hexdigest()
        else:
            raise ValueError('Track not found')

