def efficient_sort(data):
    return sorted(data)

def clean_data(data):
    cleaned_data = []
    for item in data:
        if isinstance(item, dict):
            cleaned_item = {key: value for key, value in item.items() if value is not None and value != '' and value != [] and value != {}}
            cleaned_data.append(cleaned_item)
        elif isinstance(item, list):
            cleaned_item = [value for value in item if value is not None and value != '' and value != [] and value != {}]
            cleaned_data.append(cleaned_item)
        else:
            cleaned_data.append(item)
    return cleaned_data

def calculate_ratings(data):
    ratings = {}
    for item in data:
        if isinstance(item, dict) and 'rating' in item:
            ratings[item['id']] = item['rating']
    return ratings

def update_item(data, item_id, new_data):
    for item in data:
        if item['id'] == item_id:
            item.update(new_data)
            return data
    return data

def delete_item(data, item_id):
    return [item for item in data if item['id'] != item_id]

def append_item(data, new_item):
    data.append(new_item)
    return data

def unique_items(data):
    unique_data = []
    for item in data:
        if item not in unique_data:
            unique_data.append(item)
    return unique_data

