class QuadEquationSolver:
    def __init__(self, a, b, c):
        self.a = a
        self.b = b
        self.c = c

    def discriminate(self):
        return self.b**2 - 4*self.a*self.c

    def solve(self):
        d = self.discriminate()
        if d < 0:
            return "No real roots"
        elif d == 0:
            x = -self.b / (2*self.a)
            return [x]
        else:
            x1 = (-self.b + d**0.5) / (2*self.a)
            x2 = (-self.b - d**0.5) / (2*self.a)
            return [x1, x2]

